  allLoansCustomize: IClientLoanTrackerCustomize[] = [];
  modalResult: IClientLoanTrackerCustomize[] = [];
  groupingRes: any[];
  modalView: boolean = false;
  backButtonListener: Subscription;

  async ngOnInit() {
    this.registerBackButtonListener();
    this.customizeResult();
  }
  ngOnDestroy(): void {
    //Handling The BackButton in mobile
    this.backButtonListener.unsubscribe();
  }
  groupByProperty(arr: IClientLoanTrackerCustomize[], propertyName: string) {
    const groups = arr.reduce((acc, item) => {
      const propertyValue = item[propertyName];
      if (!acc[propertyValue]) {
        acc[propertyValue] = [];
      }
      acc[propertyValue].push(item);
      return acc;
    }, {});

    const distinctValues = Object.keys(groups);
    const infoOfEveryItem = distinctValues.map((value) => groups[value][0]);
    const groupedItems = distinctValues.map((value) => groups[value]);

    return (this.groupingRes = [
      distinctValues, // all distinct Value
      infoOfEveryItem,
      groupedItems,
    ]);
  }
  customizeResult() {
    for (let i = 0; i < this.allLoans.length; ) {
      this.allLoansCustomize.push({
        loan_key: this.allLoans[i].loan_key.toString(),
        loan_code: this.allLoans[i].loan_code.toString(),
        inst_serial: this.allLoans[i].inst_serial.toString(),
        deserved_amount: this.allLoans[i].deserved_amount.toString(),
        inst_paid_total: this.allLoans[i].inst_paid_total.toString(),
        inst_am: this.allLoans[i].inst_am.toString(),
        inst_mat_date: this.allLoans[i].inst_mat_date,
        inst_status_desc: this.allLoans[i].inst_status_desc,
        loan_am: this.allLoans[i].loan_am.toString(),
        loan_status_desc: this.allLoans[i].loan_status_desc,
        loan_date: this.allLoans[i].loan_date,
      });

      this.allLoansCustomize[i].loan_am = formatNumber(
        Number(parseInt(this.allLoansCustomize[i].loan_am)),
        "en-US",
        "1.0-0"
      );
      this.allLoansCustomize[i].loan_date = this.datepipe.transform(
        this.allLoansCustomize[i].loan_date,
        "yyyy-MM-dd"
      );
      this.allLoansCustomize[i].inst_am = formatNumber(
        Number(parseInt(this.allLoansCustomize[i].inst_am)),
        "en-US",
        "1.0-0"
      );
      this.allLoansCustomize[i].inst_paid_total = formatNumber(
        Number(parseInt(this.allLoansCustomize[i].inst_paid_total)),
        "en-US",
        "1.0-0"
      );
      this.allLoansCustomize[i].deserved_amount = formatNumber(
        Number(parseInt(this.allLoansCustomize[i].deserved_amount)),
        "en-US",
        "1.0-0"
      );
      this.allLoansCustomize[i].inst_mat_date = this.datepipe.transform(
        this.allLoans[i].inst_mat_date,
        "yyyy-MM-dd"
      );
      i++;
    }
    this.groupByProperty(this.allLoansCustomize, "loan_key");
  }
  installmentDetails(i: IClientLoanTrackerCustomize) {
    this.modalResult = this.allLoansCustomize.filter(
      (x) => x.loan_key == i.loan_key
    );
    this.modalView = true;
  }
  dismissModal() {
    this.modalView = false;
  }
  sortingTable(data: IClientLoanTrackerCustomize[], param: string) {
    this.sortingService.sortByParameter(data, param);
  }
  registerBackButtonListener(): void {
    this.backButtonListener = this.platform.backButton.subscribeWithPriority(
      10,
      (next) => {
        this.backButton();
      }
    );
  }
  backButton(): void {
    if (this.modalView == true) {
      this.modalView = false;
    } else if (this.modalView == false) {
      this.router.navigate(["/home"]);
    }
  }
  escapeBtn(event: KeyboardEvent) {
    if (event.key == "Escape") {
      this.dismissModal();
    }
  }
